module RefModule (
    input clk,
    input reset,
    output [1:0] gray_count );reg [1:0] unused_binary_count;
    reg [1:0] gray_count_reg;

    always @(posedge clk) begin
        if (reset)
            unused_binary_count <= 2'b00;
        else
            unused_binary_count <= unused_binary_count + 1;
    end

    always @(*) begin
        gray_count_reg = {unused_binary_count[1], unused_binary_count[1] ^ unused_binary_count[0]};
    end

    assign gray_count = gray_count_reg;

endmodule
